module serial2parallel(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg [7:0] dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] din_tmp;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) cnt <= 4'd0;
        else if (cnt == 4'd8) cnt <= 4'd0;
        else cnt <= cnt + 1;
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) din_tmp <= 8'd0;
        else if (din_valid && cnt <= 4'd7) din_tmp <= {din_tmp[6:0], din_serial};
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dout_valid <= 1'b0;
        else if (cnt == 4'd8) dout_valid <= 1'b1;
        else dout_valid <= 1'b0;
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) dout_parallel <= 8'd0;
        else if (cnt == 4'd8) dout_parallel <= din_tmp;
    end
endmodule
